图片遮盖.Front:
{{#标题}}<div>{{标题}}</div>{{/标题}}
<div style="display: none">{{cloze:遮盖}}</div>
<div id="err"></div>
<div id="image-occlusion-container">
    {{图片}}
    <canvas id="image-occlusion-canvas"></canvas>
</div>
<script>
try {
    anki.imageOcclusion.setup();
} catch (exc) {
    document.getElementById("err").innerHTML = `加载图片遮盖时候出错，请确认是使用的是否最新版本的 Anki。<br><br>${exc}`;
}
</script>

